content:
{
  "sentences": [
    {
      "text": "今天天氣有點悶熱，心情有點不好。",
      "pinyin": "Jīntiān tiānqì yǒudiǎn mēnrè, xīnqíng yǒudiǎn bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 you3dian3 men1re4, xin1qing2 you3dian3 bu4 hao3.",
      "translation_en": "The weather is a bit stuffy today, and my mood is a little bad.",
      "translation_ko": "오늘 날씨가 좀 후덥지근해서 기분이 좀 안 좋아요."
    },
    {
      "text": "下雨天我有點緊張，因為路很滑。",
      "pinyin": "Xiàyǔ tiān wǒ yǒudiǎn jǐnzhāng, yīnwèi lù hěn huá.",
      "pinyin_numeric": "xia4yu3 tian1 wo3 you3dian3 jin3zhang1, yin1wei4 lu4 hen3 hua2.",
      "translation_en": "I'm a bit nervous on rainy days because the roads are slippery.",
      "translation_ko": "비 오는 날은 길이 미끄러워서 좀 긴장돼요."
    },
    {
      "text": "今天出太陽了，我覺得很開心，心情也比較好。",
      "pinyin": "Jīntiān chū tàiyáng le, wǒ juéde hěn kāixīn, xīnqíng yě bǐjiào hǎo.",
      "pinyin_numeric": "jin1tian1 chu1 tai4yang2 le0, wo3 jue2de5 hen3 kai1xin1, xin1qing2 ye3 bi3jiao4 hao3.",
      "translation_en": "The sun came out today, I feel very happy, and my mood is better.",
      "translation_ko": "오늘 해가 나서 기분이 좋고, 마음도 좀 나아졌어요."
    },
    {
      "text": "颱風天我有點擔心，因為風很大。",
      "pinyin": "Táifēng tiān wǒ yǒudiǎn dānxīn, yīnwèi fēng hěn dà.",
      "pinyin_numeric": "tai2feng1 tian1 wo3 you3dian3 dan1xin1, yin1wei4 feng1 hen3 da4.",
      "translation_en": "I'm a bit worried on typhoon days because the wind is strong.",
      "translation_ko": "태풍이 오는 날은 바람이 세서 좀 걱정돼요."
    },
    {
      "text": "陰天的時候我有點沒精神，想休息一下。",
      "pinyin": "Yīntiān de shíhou wǒ yǒudiǎn méi jīngshén, xiǎng xiūxí yīxià.",
      "pinyin_numeric": "yin1tian1 de5 shi2hou5 wo3 you3dian3 mei2 jing1shen2, xiang3 xiu1xi2 yi1xia4.",
      "translation_en": "On cloudy days I feel a bit low on energy and want to rest a bit.",
      "translation_ko": "흐린 날에는 좀 기운이 없어서 잠시 쉬고 싶어요."
    },
    {
      "text": "今天溫度有三十度，我覺得很熱，有點不舒服。",
      "pinyin": "Jīntiān wēndù yǒu sānshí dù, wǒ juéde hěn rè, yǒudiǎn bù shūfú.",
      "pinyin_numeric": "jin1tian1 wen1du4 you3 san1shi2 du4, wo3 jue2de5 hen3 re4, you3dian3 bu4 shu1fu2.",
      "translation_en": "Today it's 30 degrees, I feel very hot and a bit uncomfortable.",
      "translation_ko": "오늘 기온이 30도라서 너무 덥고 좀 불편해요."
    },
    {
      "text": "晴天我比較有精神，心情也比較放鬆。",
      "pinyin": "Qíngtiān wǒ bǐjiào yǒu jīngshén, xīnqíng yě bǐjiào fàngsōng.",
      "pinyin_numeric": "qing2tian1 wo3 bi3jiao4 you3 jing1shen2, xin1qing2 ye3 bi3jiao4 fang4song1.",
      "translation_en": "On sunny days I have more energy and my mood is more relaxed.",
      "translation_ko": "맑은 날에는 기운이 더 나고 기분도 더 편안해요."
    },
    {
      "text": "今天天氣很舒服，我有點開心，想出去走走。",
      "pinyin": "Jīntiān tiānqì hěn shūfú, wǒ yǒudiǎn kāixīn, xiǎng chūqù zǒuzǒu.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 shu1fu2, wo3 you3dian3 kai1xin1, xiang3 chu1qu4 zou3zou3.",
      "translation_en": "The weather is very comfortable today, I'm a bit happy and want to go out for a walk.",
      "translation_ko": "오늘 날씨가 아주 쾌적해서 좀 기분이 좋고, 밖에 나가서 산책하고 싶어요."
    },
    {
      "text": "下雨了，我忘記帶傘，有點緊張。",
      "pinyin": "Xiàyǔ le, wǒ wàngjì dài sǎn, yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "xia4yu3 le0, wo3 wang4ji4 dai4 san3, you3dian3 jin3zhang1.",
      "translation_en": "It's raining, I forgot to bring an umbrella, and I'm a bit nervous.",
      "translation_ko": "비가 왔는데 우산을 가져오는 걸 잊어버려서 좀 긴장돼요."
    },
    {
      "text": "今天天氣很冷，我有點擔心會感冒。",
      "pinyin": "Jīntiān tiānqì hěn lěng, wǒ yǒudiǎn dānxīn huì gǎnmào.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 leng3, wo3 you3dian3 dan1xin1 hui4 gan3mao4.",
      "translation_en": "The weather is very cold today, I'm a bit worried I might catch a cold.",
      "translation_ko": "오늘 날씨가 아주 추워서 감기에 걸릴까 봐 좀 걱정돼요."
    }
  ]
}
